import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.6MCaaFDc.js";const m=JSON.parse('{"title":"Hexadecimal Numbers","description":"","frontmatter":{},"headers":[],"relativePath":"practical/number-systems/hexadecimal.md","filePath":"practical/number-systems/hexadecimal.md"}'),o={name:"practical/number-systems/hexadecimal.md"};function s(n,t,i,l,c,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="hexadecimal-numbers" tabindex="-1">Hexadecimal Numbers <a class="header-anchor" href="#hexadecimal-numbers" aria-label="Permalink to &quot;Hexadecimal Numbers&quot;">​</a></h1><p>Binary is efficient for computers but hard for humans to read — <code>11111111</code> requires 8 digits to express what hex writes as <code>FF</code>. Hexadecimal (base-16) is a compact shorthand for binary used throughout computing: memory addresses, colour codes, MAC addresses, and error codes all use hex.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Hexadecimal conversions are introduced in Grade 10 and appear in most Paper 1 and Paper 2 papers. The binary↔hex shortcut (groups of 4 bits) is the key skill.</p></div><hr><h2 id="what-is-hexadecimal" tabindex="-1">What is Hexadecimal? <a class="header-anchor" href="#what-is-hexadecimal" aria-label="Permalink to &quot;What is Hexadecimal?&quot;">​</a></h2><p><strong>Hexadecimal</strong> is a <strong>base-16</strong> number system using 16 symbols:</p><table tabindex="0"><thead><tr><th>Decimal</th><th>Hex</th><th>Binary</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0000</td></tr><tr><td>1</td><td>1</td><td>0001</td></tr><tr><td>2</td><td>2</td><td>0010</td></tr><tr><td>3</td><td>3</td><td>0011</td></tr><tr><td>4</td><td>4</td><td>0100</td></tr><tr><td>5</td><td>5</td><td>0101</td></tr><tr><td>6</td><td>6</td><td>0110</td></tr><tr><td>7</td><td>7</td><td>0111</td></tr><tr><td>8</td><td>8</td><td>1000</td></tr><tr><td>9</td><td>9</td><td>1001</td></tr><tr><td>10</td><td><strong>A</strong></td><td>1010</td></tr><tr><td>11</td><td><strong>B</strong></td><td>1011</td></tr><tr><td>12</td><td><strong>C</strong></td><td>1100</td></tr><tr><td>13</td><td><strong>D</strong></td><td>1101</td></tr><tr><td>14</td><td><strong>E</strong></td><td>1110</td></tr><tr><td>15</td><td><strong>F</strong></td><td>1111</td></tr></tbody></table><blockquote><p>A = 10, B = 11, C = 12, D = 13, E = 14, F = 15</p></blockquote><p><strong>One hex digit = exactly 4 binary bits (nibble)</strong><br> This is the key relationship that makes hex ↔ binary so fast.</p><hr><h2 id="hex-→-decimal-conversion" tabindex="-1">Hex → Decimal Conversion <a class="header-anchor" href="#hex-→-decimal-conversion" aria-label="Permalink to &quot;Hex → Decimal Conversion&quot;">​</a></h2><p><strong>Method:</strong> Multiply each hex digit by its place value (power of 16), then add.</p><p>Place values (right to left): 16⁰ = 1, 16¹ = 16, 16² = 256, 16³ = 4096</p><h3 id="worked-example-2b16-→-decimal" tabindex="-1">Worked Example: <code>2B₁₆</code> → Decimal <a class="header-anchor" href="#worked-example-2b16-→-decimal" aria-label="Permalink to &quot;Worked Example: `2B₁₆` → Decimal&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Digit</th><th>B</th><th>2</th></tr></thead><tbody><tr><td>Place value</td><td>16¹ = 16</td><td>16⁰ = 1</td></tr><tr><td>Value</td><td>B = 11</td><td>2</td></tr><tr><td>× place</td><td>11 × 16 = 176</td><td>2 × 1 = 2</td></tr></tbody></table><p>Total = 176 + 2 = <strong>178</strong></p><p>So <code>2B₁₆ = 178₁₀</code></p><h3 id="worked-example-3f416-→-decimal" tabindex="-1">Worked Example: <code>3F4₁₆</code> → Decimal <a class="header-anchor" href="#worked-example-3f416-→-decimal" aria-label="Permalink to &quot;Worked Example: `3F4₁₆` → Decimal&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Digit</th><th>3</th><th>F</th><th>4</th></tr></thead><tbody><tr><td>Place value</td><td>16² = 256</td><td>16¹ = 16</td><td>16⁰ = 1</td></tr><tr><td>Value</td><td>3</td><td>15</td><td>4</td></tr><tr><td>× place</td><td>3 × 256 = 768</td><td>15 × 16 = 240</td><td>4 × 1 = 4</td></tr></tbody></table><p>Total = 768 + 240 + 4 = <strong>1012</strong></p><hr><h2 id="decimal-→-hex-conversion" tabindex="-1">Decimal → Hex Conversion <a class="header-anchor" href="#decimal-→-hex-conversion" aria-label="Permalink to &quot;Decimal → Hex Conversion&quot;">​</a></h2><p><strong>Method:</strong> Repeated division by 16 — record remainders (convert remainders &gt; 9 to A–F).</p><h3 id="worked-example-25510-→-hex" tabindex="-1">Worked Example: <code>255₁₀</code> → Hex <a class="header-anchor" href="#worked-example-25510-→-hex" aria-label="Permalink to &quot;Worked Example: `255₁₀` → Hex&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Step</th><th>Calculation</th><th>Quotient</th><th>Remainder</th></tr></thead><tbody><tr><td>1</td><td>255 ÷ 16</td><td>15</td><td><strong>15 = F</strong></td></tr><tr><td>2</td><td>15 ÷ 16</td><td>0</td><td><strong>15 = F</strong></td></tr></tbody></table><p>Read remainders <strong>bottom to top</strong>: <strong>FF</strong></p><p>So <code>255₁₀ = FF₁₆</code></p><h3 id="worked-example-101210-→-hex" tabindex="-1">Worked Example: <code>1012₁₀</code> → Hex <a class="header-anchor" href="#worked-example-101210-→-hex" aria-label="Permalink to &quot;Worked Example: `1012₁₀` → Hex&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Step</th><th>Calculation</th><th>Quotient</th><th>Remainder</th></tr></thead><tbody><tr><td>1</td><td>1012 ÷ 16</td><td>63</td><td><strong>4</strong></td></tr><tr><td>2</td><td>63 ÷ 16</td><td>3</td><td><strong>15 = F</strong></td></tr><tr><td>3</td><td>3 ÷ 16</td><td>0</td><td><strong>3</strong></td></tr></tbody></table><p>Read remainders bottom to top: <strong>3F4</strong></p><p>So <code>1012₁₀ = 3F4₁₆</code> ✓</p><hr><h2 id="binary-↔-hex-shortcut-the-key-skill" tabindex="-1">Binary ↔ Hex Shortcut (The Key Skill) <a class="header-anchor" href="#binary-↔-hex-shortcut-the-key-skill" aria-label="Permalink to &quot;Binary ↔ Hex Shortcut (The Key Skill)&quot;">​</a></h2><p><strong>Every hex digit = exactly 4 binary bits.</strong> This makes conversion between them trivial.</p><h3 id="binary-→-hex" tabindex="-1">Binary → Hex <a class="header-anchor" href="#binary-→-hex" aria-label="Permalink to &quot;Binary → Hex&quot;">​</a></h3><ol><li>Group binary digits into groups of <strong>4 from the right</strong> (pad with leading zeros if needed)</li><li>Convert each group of 4 to its hex digit</li></ol><h3 id="worked-example-101111012-→-hex" tabindex="-1">Worked Example: <code>10111101₂</code> → Hex <a class="header-anchor" href="#worked-example-101111012-→-hex" aria-label="Permalink to &quot;Worked Example: `10111101₂` → Hex&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1011 1101</span></span>\n<span class="line"><span>  B    D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>So <code>10111101₂ = BD₁₆</code></p><h3 id="worked-example-11010010112-→-hex" tabindex="-1">Worked Example: <code>1101001011₂</code> → Hex <a class="header-anchor" href="#worked-example-11010010112-→-hex" aria-label="Permalink to &quot;Worked Example: `1101001011₂` → Hex&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  11 0100 1011      (pad left: 0011 0100 1011)</span></span>\n<span class="line"><span>   3    4    B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>So <code>1101001011₂ = 34B₁₆</code></p><hr><h3 id="hex-→-binary" tabindex="-1">Hex → Binary <a class="header-anchor" href="#hex-→-binary" aria-label="Permalink to &quot;Hex → Binary&quot;">​</a></h3><p>Replace each hex digit with its <strong>4-bit binary equivalent</strong>:</p><h3 id="worked-example-a716-→-binary" tabindex="-1">Worked Example: <code>A7₁₆</code> → Binary <a class="header-anchor" href="#worked-example-a716-→-binary" aria-label="Permalink to &quot;Worked Example: `A7₁₆` → Binary&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A      7</span></span>\n<span class="line"><span>1010  0111</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Result: <code>10100111₂</code></p><h3 id="worked-example-f3c16-→-binary" tabindex="-1">Worked Example: <code>F3C₁₆</code> → Binary <a class="header-anchor" href="#worked-example-f3c16-→-binary" aria-label="Permalink to &quot;Worked Example: `F3C₁₆` → Binary&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F      3      C</span></span>\n<span class="line"><span>1111  0011  1100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Result: <code>111100111100₂</code></p><hr><h2 id="hex-in-real-computing" tabindex="-1">Hex in Real Computing <a class="header-anchor" href="#hex-in-real-computing" aria-label="Permalink to &quot;Hex in Real Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where hex is used</th><th>Example</th></tr></thead><tbody><tr><td>Memory addresses</td><td><code>0x00FF1234</code></td></tr><tr><td>RGB colours (web)</td><td><code>#FF5733</code> (red=FF, green=57, blue=33)</td></tr><tr><td>MAC addresses</td><td><code>00:1A:2B:3C:4D:5E</code></td></tr><tr><td>Error codes</td><td><code>0x0000004E</code> (Windows BSOD)</td></tr><tr><td>ASCII in hex</td><td><code>41</code> = &#39;A&#39;, <code>20</code> = space</td></tr></tbody></table><h3 id="colour-code-example" tabindex="-1">Colour Code Example <a class="header-anchor" href="#colour-code-example" aria-label="Permalink to &quot;Colour Code Example&quot;">​</a></h3><p><code>#FF5733</code> breaks into:</p><ul><li><code>FF</code> = 255 (max red)</li><li><code>57</code> = 87 (medium green)</li><li><code>33</code> = 51 (low blue)</li></ul><p>→ A warm orange-red colour.</p><hr><h2 id="summary-all-three-systems" tabindex="-1">Summary: All Three Systems <a class="header-anchor" href="#summary-all-three-systems" aria-label="Permalink to &quot;Summary: All Three Systems&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Decimal</th><th>Binary</th><th>Hex</th></tr></thead><tbody><tr><td>0</td><td>0000</td><td>0</td></tr><tr><td>5</td><td>0101</td><td>5</td></tr><tr><td>10</td><td>1010</td><td>A</td></tr><tr><td>15</td><td>1111</td><td>F</td></tr><tr><td>16</td><td>00010000</td><td>10</td></tr><tr><td>32</td><td>00100000</td><td>20</td></tr><tr><td>255</td><td>11111111</td><td>FF</td></tr><tr><td>256</td><td>100000000</td><td>100</td></tr></tbody></table><hr><h2 id="practice-exercises" tabindex="-1">Practice Exercises <a class="header-anchor" href="#practice-exercises" aria-label="Permalink to &quot;Practice Exercises&quot;">​</a></h2><p><strong>Exercise 1 — Hex to decimal</strong></p><p>Convert: a) <code>1F₁₆</code><br> b) <code>C8₁₆</code><br> c) <code>2A3₁₆</code></p><details><summary>Show solution</summary><p>a) <code>1F</code>:<br> (1 × 16) + (15 × 1) = 16 + 15 = <strong>31</strong></p><p>b) <code>C8</code>:<br> (12 × 16) + (8 × 1) = 192 + 8 = <strong>200</strong></p><p>c) <code>2A3</code>:<br> (2 × 256) + (10 × 16) + (3 × 1) = 512 + 160 + 3 = <strong>675</strong></p></details><hr><p><strong>Exercise 2 — Decimal to hex</strong></p><p>Convert: a) <code>47₁₀</code><br> b) <code>175₁₀</code><br> c) <code>1000₁₀</code></p><details><summary>Show solution</summary><p>a) 47:<br> 47 ÷ 16 = 2 rem <strong>15 (F)</strong><br> 2 ÷ 16 = 0 rem <strong>2</strong><br> Bottom to top: <strong>2F</strong> → verify: 2×16 + 15 = 47 ✓</p><p>b) 175:<br> 175 ÷ 16 = 10 rem <strong>15 (F)</strong><br> 10 ÷ 16 = 0 rem <strong>10 (A)</strong><br> Bottom to top: <strong>AF</strong> → verify: 10×16 + 15 = 175 ✓</p><p>c) 1000:<br> 1000 ÷ 16 = 62 rem <strong>8</strong><br> 62 ÷ 16 = 3 rem <strong>14 (E)</strong><br> 3 ÷ 16 = 0 rem <strong>3</strong><br> Bottom to top: <strong>3E8</strong> → verify: 3×256 + 14×16 + 8 = 768 + 224 + 8 = 1000 ✓</p></details><hr><p><strong>Exercise 3 — Binary ↔ Hex</strong></p><p>a) Convert <code>11010110₂</code> to hex<br> b) Convert <code>B4₁₆</code> to binary</p><details><summary>Show solution</summary><p>a) <code>11010110</code>:<br> Group: <code>1101 0110</code> → D = 1101, 6 = 0110 → <strong>D6₁₆</strong></p><p>b) <code>B4</code>:<br> B = <code>1011</code>, 4 = <code>0100</code> → <strong>10110100₂</strong></p><p>Verify: 10110100 = 128 + 32 + 16 + 4 = 180 = 11×16 + 4 = <strong>B4₁₆</strong> ✓</p></details><hr><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>Hex ↔ binary conversion is almost instant once you memorise the 16-entry table (0–F). The binary→hex grouping trick means you never need to go binary→decimal→hex; just group into nibbles and convert directly. When an exam gives you a hex colour code or memory address and asks for binary — this shortcut saves 90 seconds.</p></div>',76)])])}const b=e(o,[["render",s]]);export{m as __pageData,b as default};
